export default function ScannerScreen() {
  const [hasPermission, setHasPermission] = useState<boolean | null>(null);
  const [scanned, setScanned] = useState(false);
  const [result, setResult] = useState<{ status: 'success' | 'warning' | 'error'; message: string; participante?: Participante } | null>(null);
  const isFocused = useIsFocused();
  const [activeEventId, setActiveEventIdState] = useState<string | null>(null);

  useEffect(() => {
    (async () => {
      const { status } = await Camera.requestCameraPermissionsAsync();
      setHasPermission(status === 'granted');
    })();
  }, []);

  useEffect(() => {
    if (isFocused) {
      setScanned(false);
      setResult(null);
      getActiveEventId().then(setActiveEventIdState);
    }
  }, [isFocused]);

  const handleBarCodeScanned = async ({ type, data }: { type: string; data: string }) => {
    if (scanned) return;
    setScanned(true);

    try {
      const qrData = JSON.parse(data);
      const { id, eventoId } = qrData;

      if (!id || !eventoId) {
        throw new Error('QR Code inv├ílido');
      }

      if (activeEventId && eventoId !== activeEventId) {
        Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error);
        setResult({ status: 'error', message: 'Participante pertence a outro evento.' });
        return;
      }

      const checkEvent = await getEventoById(eventoId);
      if (!checkEvent) {
        Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error);
        setResult({ status: 'error', message: 'Evento n├úo existe.' });
        return;
      }

      const participant = await getParticipanteById(id);
      if (!participant) {
        Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error);
        setResult({ status: 'error', message: 'Participante n├úo encontrado.' });
        return;
      }

      if (participant.checkedIn) {
        Haptics.notificationAsync(Haptics.NotificationFeedbackType.Warning);
        setResult({ status: 'warning', message: 'Check-in j├í realizado!', participante: participant });
      } else {
        await updateCheckIn(id, 1);
        Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
        setResult({ status: 'success', message: 'Check-in confirmado com sucesso!', participante: participant });
      }

    } catch (error) {
      Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error);
      setResult({ status: 'error', message: 'QR Code inv├ílido ou corrompido.' });
    }
  };

  if (hasPermission === null) {
    return <View style={styles.container} />;
  }
  if (hasPermission === false) {
    return <Text style={{ padding: 20 }}>Acesso ├á c├ómera negado</Text>;
  }

  const renderResult = () => {
    if (!result) return null;

    let bgColor = '#fff';
    let icon = <CheckCircle size={48} color="#28a745" />;

    if (result.status === 'success') {
      bgColor = '#e8f5e9';
      icon = <CheckCircle size={48} color="#28a745" />;
    } else if (result.status === 'warning') {
      bgColor = '#fff8e1';
      icon = <AlertTriangle size={48} color="#ffc107" />;
    } else {
      bgColor = '#ffebee';
      icon = <XCircle size={48} color="#dc3545" />;
    }

    return (
      <View style={[styles.resultCard, { backgroundColor: bgColor }]}>
        {icon}
        <Text style={styles.resultTitle}>{result.message}</Text>

        {result.participante && (
          <View style={styles.participantInfo}>
            <View style={styles.participantRow}>
              <User size={20} color="#6c757d" />
              <Text style={styles.participantName}>{result.participante.nome}</Text>
            </View>
            <Text style={styles.participantRole}>{result.participante.funcao}</Text>
          </View>
        )}

        <TouchableOpacity style={styles.btnRescan} onPress={() => { setScanned(false); setResult(null); }}>
          <Text style={styles.btnRescanText}>Escanear Novamente</Text>
        </TouchableOpacity>
      </View>
    );
  };

  return (
    <View style={styles.container}>
      {isFocused && (
        <CameraView
          style={StyleSheet.absoluteFillObject}
          facing="back"
          onBarcodeScanned={scanned ? undefined : handleBarCodeScanned}
          barcodeScannerSettings={{
            barcodeTypes: ["qr"],
          }}
        />
      )}

      {!scanned && (
        <View style={styles.overlay}>
          <View style={styles.unfocusedContainer}></View>
          <View style={styles.middleContainer}>
            <View style={styles.unfocusedContainer}></View>
            <View style={styles.focusedContainer}>
              <View style={[styles.corner, styles.topLeft]} />
              <View style={[styles.corner, styles.topRight]} />
              <View style={[styles.corner, styles.bottomLeft]} />
              <View style={[styles.corner, styles.bottomRight]} />
            </View>
            <View style={styles.unfocusedContainer}></View>
          </View>
          <View style={styles.unfocusedContainer}>
            <Text style={styles.instructionText}>Posicione o QR Code dentro do quadrado</Text>
          </View>
        </View>
      )}

      {scanned && (
        <View style={styles.resultOverlay}>
          {renderResult()}
        </View>
      )}
    </View>
  );
}

